@use '../../styles/tokens' as *;

.search-bar {
  display: flex;
  align-items: center;
  height: $search-bar-height;
  padding: 0 $space-4;
  border-bottom: 1px solid $color-border;
  gap: $space-3;
}

.search-bar__icon {
  flex-shrink: 0;
  color: $color-text-tertiary;
}

.search-bar__breadcrumbs {
  display: flex;
  align-items: center;
  flex-shrink: 0;
  gap: $space-half;
}

.search-bar__breadcrumb {
  display: inline-flex;
  align-items: center;
  padding: $space-half $space-2;
  border: none;
  border-radius: $radius-sm;
  background: $color-surface-hover;
  font-family: $font-family;
  font-size: $font-sm;
  color: $color-text-secondary;
  cursor: pointer;
  white-space: nowrap;
  transition: background-color $transition-fast ease;

  &:hover {
    background: $color-border;
  }

  &:focus-visible {
    outline: 2px solid $color-accent;
    outline-offset: -1px;
  }

  &--current {
    cursor: default;

    &:hover {
      background: $color-surface-hover;
