$color-text-tertiary: #6e6e73;
$color-accent: #007aff;
$color-accent-hover: #0a84ff;
$color-destructive: #ff453a;
$color-success: #30d158;
$color-surface-footer: #1c1c1e;
$color-text-on-accent: #ffffff;
$color-text-on-accent-secondary: rgba(255, 255, 255, 0.7);
$color-kbd-background: rgba(255, 255, 255, 0.08);
$color-code-background: rgba(255, 255, 255, 0.06);
$color-tag-background: rgba(255, 255, 255, 0.1);

$font-family-mono: 'SF Mono', SFMono-Regular, ui-monospace, Menlo, monospace;

$font-weight-semibold: 600;

$space-half: 2px;
$space-1: 4px;
$space-2: 8px;
$space-3: 12px;
$space-4: 16px;
$space-5: 20px;
$space-6: 24px;
$space-7: 28px;
$space-8: 32px;

$radius-sm: 4px;
$radius-md: 8px;
$radius-lg: 12px;
$radius-xl: 16px;

$shadow-window:
  0 24px 80px rgba(0, 0, 0, 0.55),
  0 2px 12px rgba(0, 0, 0, 0.35);
$shadow-popover:
  0 12px 32px rgba(0, 0, 0, 0.45),
  0 1px 6px rgba(0, 0, 0, 0.25);

$font-family:
  -apple-system, BlinkMacSystemFont, 'SF Pro Text', 'Segoe UI', Roboto,
  Helvetica, Arial, sans-serif;

$font-xs: 11px;
$font-sm: 12px;
$font-md: 13px;
$font-lg: 15px;
$font-xl: 20px;

$search-bar-height: 46px;
$size-grid-icon: 64px;

$transition-fast: 80ms;
$transition-normal: 150ms;
$transition-slow: 250ms;

